const dbData = $input.first().json;

// 🔵 pega direto do trigger (workflow pai)
let raw = $node["When Executed by Another Workflow"].json.query ?? {};

// parse do JSON
if (typeof raw === "string") {
  raw = raw.replace(
    /"header_image_url"\s*:\s*"([^"]+)"\s*:\s*"([^"]+)"/,
    (_, a, b) => `"header_image_url":"${b}"`
  );
  raw = JSON.parse(raw);
}

// junta dados
const parsed = {
  ...raw,     // dados da IA
  ...dbData,  // dados do banco (sobrescreve id)
};

// Corrige *1* → {{1}}
if (parsed.message) {
  parsed.message = parsed.message.replace(/\*1\*/g, "{{1}}");
}

// Injeta variável
if (
  parsed.variables?.length > 0 &&
  parsed.message &&
  !parsed.message.includes("{{1}}")
) {
  parsed.message = "Olá {{1}}, " + parsed.message;
}

// Força o horário para São Paulo (-03:00) se veio com Z ou sem offset
let scheduledAt = parsed.scheduled_at ?? null;
if (scheduledAt) {
  // Remove o Z e adiciona -03:00
  // "2026-03-25T15:15:00Z"       → "2026-03-25T15:15:00-03:00"
  // "2026-03-25T15:15:00"        → "2026-03-25T15:15:00-03:00"
  // "2026-03-25T15:15:00-03:00"  → mantém (já tem offset)
  if (!/[+-]\d{2}:\d{2}$/.test(scheduledAt)) {
    scheduledAt = scheduledAt.replace(/Z$/, '') + '-03:00';
  }
}

const result = {
  evento_id: parsed.id, // 👈 banco
  name: parsed.name ?? "Disparo via IA",
  send_mode: parsed.send_mode ?? "all",
  target_status: parsed.target_status ?? null,
  scheduled_at: scheduledAt,
  message: parsed.message ?? null,
  media_type: parsed.media_type ?? null,
  header_image_url: parsed.header_image_url ?? null,
  header_media_url: parsed.header_media_url ?? null,
  nome_evento: parsed.nome_evento,
  user_id: parsed.user_id,
  whatsapp_number_id: parsed.whatsapp_number_id,
};

// variables
if (result.message && result.message.includes("{{1}}")) {
  result.variables = parsed.variables ?? ["nome_participante"];
  result.variable_samples = parsed.variable_samples ?? ["João Silva"];
}

// limpa null
const clean = Object.fromEntries(
  Object.entries(result).filter(([_, v]) => v !== null && v !== undefined)
);

return { json: clean };

