SELECT id, nome_evento, user_id, whatsapp_number_id
FROM eventos
WHERE unaccent(lower(nome_evento)) ILIKE ALL (
  ARRAY[
    {{ $json.palavras.map(p => "'%" + p + "%'").join(",") }}
  ]
)
AND status IN ('ativo', 'concluido')
ORDER BY created_at DESC
LIMIT 2

