let data = {};

// 🔥 tenta lidar com qualquer formato
try {
  if (typeof $json.query === "string") {
    let q = $json.query.trim();

    // tenta parse direto
    try {
      data = JSON.parse(q);
    } catch {
      // 🔥 tenta corrigir caracteres problemáticos
      const safe = q
        .replace(/\n/g, "\\n")
        .replace(/\r/g, "\\r")
        .replace(/\t/g, "\\t");

      try {
        data = JSON.parse(safe);
      } catch {
        data = {};
      }
    }
  } else if (typeof $json.query === "object" && $json.query !== null) {
    data = $json.query;
  }
} catch (e) {
  data = {};
}

// 🔥 fallback inteligente
const nome =
  data.nome_evento ||
  data.name ||
  data.event_name ||
  "";

// 🔥 processamento
const palavras = nome
  .toLowerCase()
  .normalize("NFD").replace(/[\u0300-\u036f]/g, "")
  .replace(/[^\w\s]/g, "") // remove pontuação
  .split(/\s+/)
  .filter(p => p.length > 3 || /\d/.test(p));

return {
  palavras
};
